#nullable enable // autogenerated

using MukioI18n;
using MVZ2.GameContent.Enemies;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Definitions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Localization;
using MVZ2.Vanilla.RandomChina;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.RandomChinaEvents
{
    [RandomChinaEventDefinition(VanillaRandomChinaEventNames.theHierophant)]
    public class TheHierophantEvent : RandomChinaEventDefinition
    {
        public TheHierophantEvent(string nsp, string path) : base(nsp, path, NAME, DESCRIPTION)
        {
        }
        public override void Run(Entity contraption, RandomGenerator rng)
        {
            var level = contraption.Level;
            var spawnParams = contraption.GetSpawnParams();
            for (int lane = 0; lane < level.GetMaxLaneCount(); lane++)
            {
                var position = level.GetEntityGridPosition(0, lane);
                contraption.Spawn(VanillaEnemyID.mesmerizer, position, spawnParams);
            }
            contraption.PlaySound(VanillaSoundID.mindControl);
        }
        [TranslateMsg("随机瓷器事件名称", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_NAME)]
        public const string NAME = "V-教皇";
        [TranslateMsg("随机瓷器事件描述", VanillaStrings.CONTEXT_RANDOM_CHINA_EVENT_DESCRIPTION)]
        public const string DESCRIPTION = "每行召唤一个友方的催眠者";
    }
}
